import { Bookmark, RefreshCw, AlertCircle, Loader2, Search, Settings, Moon, Sun, ChevronDown, ChevronUp, Sparkles, X, History, Clock, Trash2, Mic, Volume2, Key, Check, Zap, Database, Book, FlaskConical, Library, Building2, Languages, Palette, CalendarClock, ArrowUp, Info, BookOpen, Download, Workflow, StickyNote, Bell, GraduationCap, Quote, Lock, Unlock, FileText, SlidersHorizontal, Microscope, Radar, ArrowLeft, BrainCircuit, WifiOff, Eye, Plus, Tag, ArrowUpCircle, ArrowDownCircle, GripVertical, Undo2, User, Home, LayoutGrid, ScanEye, Layers, Filter, Calendar, List, ArrowRight, RotateCcw, Activity, ExternalLink, ShieldCheck, Type, Newspaper, Globe } from 'lucide-react';
import { motion, AnimatePresence, LayoutGroup } from 'framer-motion';
import { App as CapacitorApp } from '@capacitor/app';

// Services
import { fetchLatestNephrologyNews, verifyGeminiKey, generateGeminiSummary, refinePicoTerms, translateSimpleQuery, searchMedicalGoogle } from './services/geminiService';
import { fetchPubMedArticles } from './services/pubmedService';
import { fetchOpenAlexArticles } from './services/openAlexService';
