               <button onClick={() => fetchNews()} disabled={loading} className="rounded-xl bg-blue-600 p-2.5 text-white shadow-lg"><RefreshCw size={20} className={loading ? 'animate-spin' : ''}/></button>
             </div>
          </header>

          <div 
