                    <div className="fixed left-0 right-0 top-11 z-40 -mx-4 border-b p-1 backdrop-blur-xl dark:bg-slate-950/80 bg-white/80 lg:sticky lg:top-0 lg:mx-0">
                        <div ref={topicContainerRef} className="no-scrollbar flex items-center gap-0 overflow-x-auto px-4 py-2">
                           {topics.map(topic => (
                              <div key={topic} className="relative group shrink-0">
                                  <button 
