import { ResearchUpdate, Article, Topic } from "../types";
import { getClinicalTrialsQuery } from "../utils/searchContexts";

const CT_API_BASE = 'https://clinicaltrials.gov/api/v2/studies';

export const fetchClinicalTrials = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string
): Promise<ResearchUpdate> => {
  try {
    let condition = customQuery || getClinicalTrialsQuery(topic);

    // Fix: Remove PubMed-specific date range filters that cause 400 errors in ClinicalTrials.gov API
    condition = condition.replace(/\s*AND\s*\(?\"\d{4}\"\[Date\s*-\s*Publication\]\s*:\s*\"3000\"\[Date\s*-\s*Publication\]\)?/gi, '');

    // Sanitize: Remove parentheses as API v2 is sensitive
    condition = condition.replace(/[()]/g, '').trim();

    if (!condition) {
        return { summary: "No search condition provided.", articles: [] };
    }

    // Explicitly request fields to ensure we get references and results info
    // identificationModule: nctId, title, org
    // descriptionModule: summary
    // statusModule: dates
    // referencesModule: sponsor provided refs
    // derivedSection: NLM curated refs (results)
    const fields = [
        'protocolSection.identificationModule',
        'protocolSection.descriptionModule',
        'protocolSection.statusModule',
        'protocolSection.referencesModule',
        'derivedSection.referenceModule'
    ].join(',');

    // Use query.term instead of query.cond for broader search
    const url = `${CT_API_BASE}?query.term=${encodeURIComponent(condition)}&pageSize=40&fields=${fields}`;

    const response = await fetch(url);

    if (!response.ok) {
        if (response.status === 400) {
            console.debug(`ClinicalTrials API 400. Term: ${condition}`);
            return { summary: "ClinicalTrials query format adjusted.", articles: [] };
        }
        throw new Error(`ClinicalTrials API Error: ${response.status}`);
    }

    const data = await response.json();
    const studies = data.studies || [];

    if (studies.length === 0) {
      return { summary: "No clinical trials found.", articles: [] };
    }

    const articles: Article[] = studies.map((study: any) => {
      const protocol = study.protocolSection;
      const derived = study.derivedSection;

      const id = protocol?.identificationModule?.nctId || 'N/A';
      const title = protocol?.identificationModule?.briefTitle || 'Untitled Clinical Trial';
      let summary = protocol?.descriptionModule?.briefSummary || 'No summary provided.';
      const org = protocol?.identificationModule?.organization?.fullName || 'Unknown Sponsor';
      const date = protocol?.statusModule?.lastUpdateSubmitDate || 'N/A';

      // --- EXTRACT ASSOCIATED PUBLICATIONS ---
      const pubList: string[] = [];

      // 1. Derived References (NLM Curated - Highly likely to be results)
      if (derived?.referenceModule?.references) {
          derived.referenceModule.references.forEach((ref: any) => {
              if (ref.citation) {
                  pubList.push(`[RESULT/INDEXED] ${ref.citation} ${ref.pmid ? `(PMID: ${ref.pmid})` : ''}`);
              }
          });
      }

      // 2. Protocol References (Provided by Sponsor - Background or Results)
      if (protocol?.referencesModule?.references) {
           protocol.referencesModule.references.forEach((ref: any) => {
               // Construct simple signature to avoid duplicates
               const citationStart = ref.citation?.substring(0, 50) || "";
               const isDuplicate = pubList.some(p => p.includes(citationStart));

               if (!isDuplicate && ref.citation) {
                   const typeTag = ref.type ? `[${ref.type}]` : '[REF]';
                   pubList.push(`${typeTag} ${ref.citation} ${ref.pmid ? `(PMID: ${ref.pmid})` : ''}`);
               }
           });
      }

      // Append publications to summary if found
      if (pubList.length > 0) {
          const header = language === 'es' ? 'Publicaciones Asociadas' : 'Associated Publications';
          summary += `\n\n${header}:\n` + pubList.map(p => `• ${p}`).join('\n');
      }

      return {
        id: `ct-${id}`,
        title: `[TRIAL] ${title}`,
        summary: summary,
        source: "ClinicalTrials.gov",
        authors: org,
        url: `https://clinicaltrials.gov/study/${id}`,
        date: date,
        category: 'Clinical Trial',
        relevanceScore: 90,
        topic: typeof topic === 'string' ? topic : 'General',
        isFree: true 
      };
    });

    return {
      summary: `ClinicalTrials.gov: ${articles.length} studies.`,
      articles: articles
    };

  } catch (error) {
    console.debug("ClinicalTrials Service Info:", error);
    return { summary: "Error fetching ClinicalTrials", articles: [] };
  }
};

